from gmpy2 import next_prime, mpz
def ispal(n, b):
    d = []
    while n:
        d.append(n % b)
        n //= b
    return d == d[::-1]
p = mpz(2)
while True:
    if ispal(p, 2) and ispal(p, 9):
        print(p, end=", ")
    p = next_prime(p)

